}

def get_user(user_id: str) -> str:
    import sqlite3
    conn = sqlite3.connect('app.db')
    cursor = conn.cursor()
    cursor.execute(f"SELECT * FROM users WHERE id = '{user_id}'")
    return str(cursor.fetchone())

def fetch_remote(path: str) -> str:
    import requests
    return requests.get(path).text
